BEGIN; ALTER TABLE public.inventory_transactions ADD COLUMN IF NOT EXISTS shipment_line_no integer; COMMENT ON COLUMN public.inventory_transactions.shipment_line_no IS 'Thu tu dong hang tren phieu chuyen; dung de in lai dung thu tu da tao hoac dieu chinh.'; CREATE INDEX IF NOT EXISTS idx_inventory_transactions_shipment_line_no ON public.inventory_transactions(shipment_id, shipment_line_no) WHERE shipment_id IS NOT NULL AND tx_type = 'out' AND adjusted_from_transaction_id IS NULL AND deleted_at IS NULL; WITH ranked AS ( SELECT t.id, (row_number() OVER ( PARTITION BY t.shipment_id ORDER BY lower(COALESCE(p.name, '')), lower(COALESCE(p.sku, '')), t.id ))::integer AS line_no FROM public.inventory_transactions t LEFT JOIN public.products p ON p.id = t.product_id WHERE t.shipment_id IS NOT NULL AND t.tx_type = 'out' AND t.adjusted_from_transaction_id IS NULL AND t.deleted_at IS NULL AND t.shipment_line_no IS NULL ) UPDATE public.inventory_transactions t SET shipment_line_no = ranked.line_no FROM ranked WHERE t.id = ranked.id; DO $$ BEGIN IF to_regprocedure('public.shipment_outbound_delivery_core_20260722(jsonb,uuid,uuid,uuid,text,text,text,text,text,date,uuid)') IS NULL THEN RAISE EXCEPTION 'Thieu core shipment_outbound_delivery_core_20260722. Can cai migration an toan chuyen hang truoc.'; END IF; END $$; CREATE OR REPLACE FUNCTION public.shipment_outbound_delivery( p_payload jsonb, p_customer_id uuid, p_entity_id uuid, p_vehicle_id uuid DEFAULT NULL, p_driver_1_name text DEFAULT NULL, p_driver_2_name text DEFAULT NULL, p_assistant_1_name text DEFAULT NULL, p_assistant_2_name text DEFAULT NULL, p_note text DEFAULT NULL, p_shipment_date date DEFAULT (now() AT TIME ZONE 'Asia/Ho_Chi_Minh')::date, p_existing_shipment_id uuid DEFAULT NULL ) RETURNS jsonb LANGUAGE plpgsql SECURITY DEFINER SET search_path = public, pg_temp AS $$ DECLARE v_result jsonb; v_shipment_id uuid; v_numbered_count integer; v_active_count integer; BEGIN IF auth.uid() IS NULL OR NOT public.is_manager() THEN RAISE EXCEPTION 'Ban khong co quyen tao chuyen hang.' USING ERRCODE = '42501'; END IF; IF p_payload IS NULL OR jsonb_typeof(p_payload) <> 'array' OR jsonb_array_length(p_payload) = 0 THEN RAISE EXCEPTION 'Du lieu chuyen hang khong hop le.'; END IF; IF EXISTS ( SELECT 1 FROM ( SELECT NULLIF(e.item->>'plan_id', '')::uuid AS plan_id, count(*) FROM jsonb_array_elements(p_payload) AS e(item) GROUP BY 1 HAVING count(*) > 1 ) duplicated ) THEN RAISE EXCEPTION 'Mot ma ke hoach chi duoc xuat hien mot lan tren chuyen.'; END IF; IF p_existing_shipment_id IS NOT NULL THEN RAISE EXCEPTION 'Chuc nang ghep hang vao chuyen da tat. Hay dieu chinh tai Nhat ky giao hang.'; END IF; IF p_vehicle_id IS NULL THEN RAISE EXCEPTION 'Vui long chon xe.'; END IF; PERFORM pg_advisory_xact_lock(hashtextextended(p_vehicle_id::text || ':' || COALESCE(p_shipment_date::text, ''), 20260722)); v_result := public.shipment_outbound_delivery_core_20260722( p_payload, p_customer_id, p_entity_id, p_vehicle_id, p_driver_1_name, p_driver_2_name, p_assistant_1_name, p_assistant_2_name, p_note, p_shipment_date, p_existing_shipment_id ); v_shipment_id := NULLIF(v_result->>'shipment_id', '')::uuid; IF v_shipment_id IS NULL THEN RAISE EXCEPTION 'Tao chuyen thanh cong nhung khong nhan duoc ma chuyen de luu thu tu dong.'; END IF; UPDATE public.inventory_transactions t SET shipment_line_no = x.line_no::integer FROM jsonb_array_elements(p_payload) WITH ORDINALITY AS x(item, line_no) WHERE t.shipment_id = v_shipment_id AND t.delivery_plan_id = NULLIF(x.item->>'plan_id', '')::uuid AND t.tx_type = 'out' AND t.adjusted_from_transaction_id IS NULL AND t.deleted_at IS NULL; GET DIAGNOSTICS v_numbered_count = ROW_COUNT; SELECT count(*) INTO v_active_count FROM public.inventory_transactions t WHERE t.shipment_id = v_shipment_id AND t.tx_type = 'out' AND t.adjusted_from_transaction_id IS NULL AND t.deleted_at IS NULL; IF v_numbered_count <> v_active_count OR v_active_count <> jsonb_array_length(p_payload) THEN RAISE EXCEPTION 'Khong luu du thu tu dong cua chuyen; toan bo thao tac da duoc hoan tac.'; END IF; RETURN v_result; END $$; REVOKE ALL ON FUNCTION public.shipment_outbound_delivery_core_20260722(jsonb,uuid,uuid,uuid,text,text,text,text,text,date,uuid) FROM PUBLIC, anon, authenticated; REVOKE ALL ON FUNCTION public.shipment_outbound_delivery(jsonb,uuid,uuid,uuid,text,text,text,text,text,date,uuid) FROM PUBLIC, anon, authenticated; GRANT EXECUTE ON FUNCTION public.shipment_outbound_delivery(jsonb,uuid,uuid,uuid,text,text,text,text,text,date,uuid) TO authenticated; DO $$ DECLARE v_current_oid oid := to_regprocedure('public.adjust_shipment_items_v1(uuid,jsonb,text)'); BEGIN IF to_regprocedure('public.adjust_shipment_items_core_20260723(uuid,jsonb,text)') IS NULL THEN IF v_current_oid IS NULL THEN RAISE EXCEPTION 'Thieu RPC adjust_shipment_items_v1. Can cai migration dieu chinh chuyen truoc.'; END IF; IF pg_get_functiondef(v_current_oid) ILIKE '%p.customer_id IS NOT DISTINCT FROM v_shipment.customer_id%' THEN RAISE EXCEPTION 'RPC dieu chinh chuyen van la ban loc sai theo khach dai dien. Hay chay migration 20260723_fix_shipment_correction_all_daily_plans.sql truoc.'; END IF; ALTER FUNCTION public.adjust_shipment_items_v1(uuid,jsonb,text) RENAME TO adjust_shipment_items_core_20260723; END IF; END $$; CREATE OR REPLACE FUNCTION public.adjust_shipment_items_v1( p_shipment_id uuid, p_lines jsonb, p_reason text ) RETURNS jsonb LANGUAGE plpgsql SECURITY DEFINER SET search_path = public, pg_temp AS $$ DECLARE v_result jsonb; v_numbered_count integer; v_active_count integer; BEGIN IF auth.uid() IS NULL OR NOT public.is_manager() THEN RAISE EXCEPTION 'Ban khong co quyen dieu chinh hang tren chuyen.' USING ERRCODE = '42501'; END IF; v_result := public.adjust_shipment_items_core_20260723(p_shipment_id, p_lines, p_reason); UPDATE public.inventory_transactions t SET shipment_line_no = x.line_no::integer FROM jsonb_array_elements(p_lines) WITH ORDINALITY AS x(item, line_no) WHERE t.shipment_id = p_shipment_id AND t.delivery_plan_id = NULLIF(x.item->>'plan_id', '')::uuid AND t.tx_type = 'out' AND t.adjusted_from_transaction_id IS NULL AND t.deleted_at IS NULL; GET DIAGNOSTICS v_numbered_count = ROW_COUNT; SELECT count(*) INTO v_active_count FROM public.inventory_transactions t WHERE t.shipment_id = p_shipment_id AND t.tx_type = 'out' AND t.adjusted_from_transaction_id IS NULL AND t.deleted_at IS NULL; IF v_numbered_count <> v_active_count THEN RAISE EXCEPTION 'Khong luu du thu tu dong sau dieu chinh; toan bo thao tac da duoc hoan tac.'; END IF; RETURN v_result; END $$; REVOKE ALL ON FUNCTION public.adjust_shipment_items_core_20260723(uuid,jsonb,text) FROM PUBLIC, anon, authenticated; REVOKE ALL ON FUNCTION public.adjust_shipment_items_v1(uuid,jsonb,text) FROM PUBLIC, anon, authenticated; GRANT EXECUTE ON FUNCTION public.adjust_shipment_items_v1(uuid,jsonb,text) TO authenticated; NOTIFY pgrst, 'reload schema'; COMMIT;
